func (c *configContainer) get(key string) (interface{}, error) {
	if len(key) == 0 {
		return nil, config.KeyNotFoundError
	}

	segs := strings.Split(key, keySeparator)
	t, err := subTree(c.t, segs[0:len(segs)-1])
	if err != nil {
		return nil, err
	}
	return t.Get(segs[len(segs)-1]), nil
}
